import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"Impostare un Ambiente di Sviluppo","description":"Una guida passo per passo su come impostare un ambiente di sviluppo per creare mod usando Fabric.","frontmatter":{"title":"Impostare un Ambiente di Sviluppo","description":"Una guida passo per passo su come impostare un ambiente di sviluppo per creare mod usando Fabric.","authors":["2xsaiko","Andrew6rant","asiekierka","Daomephsta","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","TelepathicGrunt"],"authors-nogithub":["siglong"],"files":[]},"headers":[],"relativePath":"it_it/1.21.8/develop/getting-started/setting-up-a-development-environment.md","filePath":"versions/1.21.8/translated/it_it/develop/getting-started/setting-up-a-development-environment.md","lastUpdated":1760721669000}`);var o={name:`it_it/1.21.8/develop/getting-started/setting-up-a-development-environment.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Impostare un Ambiente di Sviluppo <a class="header-anchor" href="#h1" aria-label="Permalink to “Impostare un Ambiente di Sviluppo”">​</a></h1><p>Per iniziare a sviluppare mod con Fabric, avrai bisogno d&#39;impostare un ambiente di sviluppo usando IntelliJ IDEA.</p><h2 id="installing-jdk-21" tabindex="-1">Installare JDK 21 <a class="header-anchor" href="#installing-jdk-21" aria-label="Permalink to “Installare JDK 21”">​</a></h2><p>Per sviluppare mod per Minecraft 1.21.4, avrai bisogno del JDK 21.</p><p>Se ti serve aiuto nell&#39;installare Java, puoi fare riferimento alle varie guide per installazione di Java nella <a href="./../../players/index">sezione guide per il giocatore</a>.</p><h2 id="installing-intellij-idea" tabindex="-1">Installare IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “Installare IntelliJ IDEA”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Ovviamente puoi usare altri IDE, come Eclipse o Visual Studio Code, ma la maggior parte delle pagine su questo sito di documentazione supporrà che stai usando IntelliJ IDEA - dovresti fare riferimento alla documentazione del tuo IDE se ne stai usando un altro.</p></div><p>Se non hai IntelliJ IDEA installato, puoi scaricarlo dal <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">sito ufficiale</a> - segui i passaggi per l&#39;installazione sul tuo sistema operativo.</p><p>L&#39;edizione Community di IntelliJ IDEA è gratuita e open-source, ed è la versione consigliata per il modding con Fabric.</p><p>Potresti dover scorrere giù per trovare il link per scaricare l&#39;edizione Community - ha il seguente aspetto:</p><p><img src="/assets/develop/getting-started/idea-community.png" alt="Prompt per Scaricare l&#39;Edizione Community di IDEA" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">Installare i Plugin IDEA <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “Installare i Plugin IDEA”">​</a></h2><p>Anche se questi plugin non sono strettamente necessari, essi rendono il modding con Fabric molto più semplice - dovresti installarli.</p><h3 id="minecraft-development" tabindex="-1">Minecraft Development <a class="header-anchor" href="#minecraft-development" aria-label="Permalink to “Minecraft Development”">​</a></h3><p>Il plugin Minecraft Development fornisce supporto per il modding con Fabric, ed è il plugin più importante da installare.</p><p>Puoi installarlo aprendo IntelliJ IDEA, e poi navigando a <code>File &gt; Impostazioni &gt; Plugin &gt; Scheda Marketplace</code> - cerca <code>Minecraft Development</code> nella barra di ricerca, e poi clicca il pulsante <code>Installa</code>.</p><p>In alternativa, puoi scaricarlo dalla <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">pagina del plugin</a> e poi installarlo navigando a <code>File &gt; Impostazioni &gt; Plugin &gt; Installa Plugin Dal Disco</code>.</p>`,17)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};